from dataclasses import dataclass
from enum import Enum
from datetime import datetime

class L2DiagnosisOutcome(str, Enum):
    RESOLVED_USAGE_ISSUE    = "resolved_usage_issue"
    KB_GAP_FLAGGED          = "kb_gap_flagged"
    BUG_FILED               = "bug_filed"
    NEEDS_MORE_CUSTOMER_INFO = "needs_more_customer_info"

@dataclass
class L2DiagnosisResult:
    ticket_id: str
    diagnosed_by: str
    diagnosed_at: datetime
    outcome: L2DiagnosisOutcome
    findings: str             # 2–4 sentences: what was found
    log_affected_requests_per_day: int | None
    confirmed_model_version: str | None

    # Populated based on outcome
    resolution_applied: str | None = None    # for RESOLVED
    kb_gap_description: str | None = None    # for KB_GAP_FLAGGED
    bug_id: str | None = None                # for BUG_FILED
    additional_info_needed: list[str] | None = None  # for NEEDS_MORE

    def is_complete(self) -> bool:
        if self.outcome == L2DiagnosisOutcome.RESOLVED_USAGE_ISSUE:
            return bool(self.resolution_applied)
        if self.outcome == L2DiagnosisOutcome.KB_GAP_FLAGGED:
            return bool(self.kb_gap_description)
        if self.outcome == L2DiagnosisOutcome.BUG_FILED:
            return bool(self.bug_id)
        if self.outcome == L2DiagnosisOutcome.NEEDS_MORE_CUSTOMER_INFO:
            return bool(self.additional_info_needed)
        return False

from dataclasses import dataclass
from datetime import datetime, timedelta
from enum import Enum

class CustomerUpdateStatus(str, Enum):
    INVESTIGATING          = "investigating"
    FIX_IN_PROGRESS        = "fix_in_progress"
    WORKAROUND_AVAILABLE   = "workaround_available"
    FIX_DEPLOYED           = "fix_deployed"
    WILL_NOT_FIX           = "will_not_fix"

@dataclass
class CustomerUpdate:
    ticket_id: str
    bug_id: str | None
    status: CustomerUpdateStatus
    message: str             # customer-facing text; no internal jargon
    next_update_by: datetime | None

    UPDATE_INTERVAL_HOURS = {
        "P0": 1,
        "P1": 4,
        "P2": 24,
    }

    @classmethod
    def investigating(cls, ticket_id: str, bug_id: str, priority: str) -> "CustomerUpdate":
        interval = cls.UPDATE_INTERVAL_HOURS.get(priority, 24)
        return cls(
            ticket_id=ticket_id,
            bug_id=bug_id,
            status=CustomerUpdateStatus.INVESTIGATING,
            message=(
                "We have confirmed this is a product issue and our engineering team is investigating. "
                f"We will provide an update within {interval} hour(s)."
            ),
            next_update_by=datetime.utcnow() + timedelta(hours=interval),
        )

    @classmethod
    def fix_deployed(cls, ticket_id: str, bug_id: str, fix_description: str) -> "CustomerUpdate":
        return cls(
            ticket_id=ticket_id,
            bug_id=bug_id,
            status=CustomerUpdateStatus.FIX_DEPLOYED,
            message=f"The issue has been resolved. {fix_description} Please let us know if you continue to experience any problems.",
            next_update_by=None,
        )

from dataclasses import dataclass
from datetime import datetime

@dataclass
class DuplicateCheck:
    report: CustomerReport
    tracker  # BugTracker instance

    def find_matching_bug(self) -> str | None:
        """
        Returns the bug_id of an existing open bug that this report likely duplicates,
        or None if no match found.
        Matching heuristic: same model_id + same issue category + filed within 30 days.
        """
        if self.report.affected_model_id is None:
            return None
        # In practice this queries the bug tracker; simplified here
        candidates = self.tracker.query_open_bugs(
            model_id=self.report.affected_model_id,
        )
        for bug in candidates:
            if self._symptoms_overlap(bug):
                return bug["bug_id"]
        return None

    def _symptoms_overlap(self, bug: dict) -> bool:
        # Simplified: checks if error_code matches or title tokens overlap
        if self.report.error_code and bug.get("error_code") == self.report.error_code:
            return True
        report_tokens = set((self.report.raw_message or "").lower().split())
        bug_tokens = set(bug.get("title", "").lower().split())
        return len(report_tokens & bug_tokens) >= 3

def link_or_file(report: CustomerReport, tracker) -> dict:
    check = DuplicateCheck(report=report, tracker=tracker)
    existing_bug_id = check.find_matching_bug()
    if existing_bug_id:
        tracker.link_report_to_bug(report.report_id, existing_bug_id)
        return {"action": "linked", "bug_id": existing_bug_id}
    return {"action": "new_intake", "bug_id": None}

from dataclasses import dataclass
from datetime import datetime
from enum import Enum

class SpecialTrack(str, Enum):
    SAFETY_POLICY  = "safety_policy"
    PRIVACY_DATA   = "privacy_data"

@dataclass
class SpecialTrackEscalation:
    report_id: str
    track: SpecialTrack
    received_at: datetime
    prompt_preserved: bool      # safety: raw prompt stored verbatim
    legal_hold_placed: bool     # privacy: ticket locked from further edits

    # Escalation contacts
    escalated_to: list[str]     # handles paged
    escalated_at: datetime | None = None

    ACKNOWLEDGMENT_SLA_MIN = {
        SpecialTrack.SAFETY_POLICY: 30,
        SpecialTrack.PRIVACY_DATA: 30,
    }
    ESCALATION_SLA_MIN = {
        SpecialTrack.SAFETY_POLICY: 60,    # to Policy team
        SpecialTrack.PRIVACY_DATA: 30,     # to Privacy + Security
    }

    def validate(self) -> list[str]:
        errors = []
        if self.track == SpecialTrack.SAFETY_POLICY and not self.prompt_preserved:
            errors.append("Safety reports must preserve the exact prompt verbatim")
        if self.track == SpecialTrack.PRIVACY_DATA and not self.legal_hold_placed:
            errors.append("Privacy reports must have legal hold placed before editing")
        if not self.escalated_to:
            errors.append("escalated_to must list at least one contact")
        return errors
